#!/usr/bin/env node
// Concatenates the static JS files referenced by index.html into a single
// bundle, content-hashes the output, and stamps the hash into index.html's
// cache-bust query string. Output lives in the SAME directory as the
// originals (assets/js/) so that relative dynamic imports (e.g.
// `import("./leisure/wasm-shim.js")` inside app.js) keep resolving the same
// way they did before bundling.
//
// Usage:   node tools/build-bundle.mjs
// Or:      npm run build:bundle

import { existsSync, readFileSync, writeFileSync, statSync } from "node:fs";
import { createHash } from "node:crypto";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const repoRoot = resolve(dirname(fileURLToPath(import.meta.url)), "..");

// Order MUST match the original <script> tag order in index.html. app.js is
// last because it depends on globals populated by the data files above.
const SOURCES = [
  "assets/js/passes-data.js",
  "assets/js/japan-passes.js",
  "assets/js/uk-ireland-passes.js",
  "assets/js/japan-scenic-drives.js",
  "assets/js/uk-ireland-scenic-drives.js",
  "assets/js/swiss-pois.js",
  "assets/js/french-pois.js",
  "assets/js/italy-pois.js",
  "assets/js/austrian-pois.js",
  "assets/js/japan-pois.js",
  "assets/js/uk-pois.js",
  "assets/js/irish-pois.js",
  "assets/js/passes-cams.js",
  "assets/js/pass-icons.js",
  "assets/js/app.js",
];

const BUNDLE_REL = "assets/js/itinera.bundle.js";
const INDEX_HTML = resolve(repoRoot, "index.html");
const SCRIPT_TAG_LINE_REGEX =
  /<script src="assets\/js\/itinera\.bundle\.js\?v=([^"]+)" defer><\/script>/;

function readSource(rel) {
  const abs = resolve(repoRoot, rel);
  if (!existsSync(abs)) throw new Error(`Missing source: ${rel}`);
  // Normalize to LF so the bundle is byte-identical across Windows/Linux
  // builds (git autocrlf may otherwise put CRLF in working-tree files on
  // Windows). The bundle is text; line endings carry no semantic meaning.
  return readFileSync(abs, "utf8").replace(/\r\n/g, "\n");
}

function buildBundle() {
  const parts = [];
  parts.push("// Auto-generated by tools/build-bundle.mjs. Do not edit by hand.\n");
  parts.push(`// Built from ${SOURCES.length} sources in this order:\n`);
  for (const src of SOURCES) parts.push(`//   - ${src}\n`);
  parts.push("\n");
  for (const rel of SOURCES) {
    const content = readSource(rel);
    parts.push(`/* ====== begin ${rel} ====== */\n`);
    parts.push(content);
    if (!content.endsWith("\n")) parts.push("\n");
    parts.push(`/* ====== end   ${rel} ====== */\n;\n`);
  }
  return parts.join("");
}

function main() {
  const bundle = buildBundle();
  const outPath = resolve(repoRoot, BUNDLE_REL);
  writeFileSync(outPath, bundle, "utf8");

  const hash = createHash("sha256").update(bundle).digest("hex").slice(0, 12);
  const size = statSync(outPath).size;
  console.log(
    `Bundle: ${BUNDLE_REL} — ${size.toLocaleString()} bytes (${(size / 1024).toFixed(1)} KB), hash ${hash}`,
  );

  if (!existsSync(INDEX_HTML)) {
    console.warn(`Skipping index.html stamp: ${INDEX_HTML} not found.`);
    return;
  }
  const before = readFileSync(INDEX_HTML, "utf8");
  if (!SCRIPT_TAG_LINE_REGEX.test(before)) {
    console.warn(
      "index.html does not contain the bundle <script> tag; update index.html to reference " +
        BUNDLE_REL +
        " then re-run.",
    );
    return;
  }
  const after = before.replace(
    SCRIPT_TAG_LINE_REGEX,
    `<script src="assets/js/itinera.bundle.js?v=${hash}" defer></script>`,
  );
  if (after !== before) {
    writeFileSync(INDEX_HTML, after, "utf8");
    console.log(`Stamped bundle cache-bust in index.html: v=${hash}`);
  }
}

main();
